import{_ as t,o as r,c as i,a4 as a,a9 as l,ag as s,af as o}from"./chunks/framework.CIB7elcA.js";const g=JSON.parse('{"title":"MusicFree 插件","description":"","frontmatter":{"outline":"deep"},"headers":[],"relativePath":"plugin.md","filePath":"plugin.md"}'),d={name:"plugin.md"};function c(n,e,h,m,p,u){return r(),i("div",null,[...e[0]||(e[0]=[a('<h1 id="musicfree-插件" tabindex="-1">MusicFree 插件 <a class="header-anchor" href="#musicfree-插件" aria-label="Permalink to “MusicFree 插件”">​</a></h1><p><strong>插件是 MusicFree 的核心扩展机制</strong>：平台搜索下载、元数据刮削、歌单导入等能力均由第三方 WASM 插件提供，通过 <a href="/music-free-site/plugin-registry.html">插件注册表</a> 订阅安装。</p><p>相关文档：<a href="/music-free-site/plugin-registry.html">注册表</a> · <a href="/music-free-site/plugin-collection.html">第三方插件合集</a> · <a href="/music-free-site/plugin-orchestration.html">插件编排</a> · <a href="/music-free-site/plugin-development.html">插件开发</a></p><h2 id="插件提供的能力" tabindex="-1">插件提供的能力 <a class="header-anchor" href="#插件提供的能力" aria-label="Permalink to “插件提供的能力”">​</a></h2><table tabindex="0"><thead><tr><th>产品能力</th><th>宿主接口</th><th>典型插件</th></tr></thead><tbody><tr><td>在线搜索 / 下载入库</td><td><code>RemoteSearch</code>、<code>RemoteDownload</code></td><td><code>mf-plugin-gomusicdl</code> 等</td></tr><tr><td>单曲元数据、封面、歌词</td><td><code>ScraperSong</code>、<code>GetCover</code>、<code>GetLyrics</code></td><td>网易云、QQ 音乐、MusicBrainz 等</td></tr><tr><td>专辑信息刮削</td><td><code>GetAlbumInfo</code></td><td>同上刮削类插件</td></tr><tr><td>艺术家信息与头像</td><td><code>GetArtistInfo</code></td><td>同上刮削类插件</td></tr><tr><td>歌单 URL 导入 / 同步</td><td><code>FetchPlaylist</code></td><td><code>mf-plugin-netease</code>、<code>mf-plugin-qqmusic</code> 等</td></tr></tbody></table><p>后期与第三方平台的交互也将主要通过插件扩展。</p><p><img src="'+l+'" alt=""></p><h2 id="插件商店" tabindex="-1">插件商店 <a class="header-anchor" href="#插件商店" aria-label="Permalink to “插件商店”">​</a></h2><p>插件商店展示已订阅注册表中的全部插件，支持安装、启用、配置 JSON 凭据。</p><ul><li><strong>订阅注册表</strong>：在商店设置中添加一个或多个 <code>registry.json</code> URL，详见 <a href="/music-free-site/plugin-registry.html">插件注册表</a>。</li><li><strong>常用注册表与插件说明</strong>：见 <a href="/music-free-site/plugin-collection.html">第三方插件合集</a>。</li></ul><p><img src="'+s+'" alt=""></p><hr><h2 id="插件编排" tabindex="-1">插件编排 <a class="header-anchor" href="#插件编排" aria-label="Permalink to “插件编排”">​</a></h2><p>当多个插件实现同一类能力时，可在 <strong>插件编排</strong> 中为五个维度（基础信息、歌词、封面、专辑、艺术家）分别指定<strong>有序插件链</strong>，按链尝试直至命中。</p><ul><li>远程搜索 / 下载、歌单导入<strong>不走</strong>五维编排，见各功能页说明。</li><li>详细规则、配置 JSON 与排错：见 <a href="/music-free-site/plugin-orchestration.html">插件编排</a>。</li></ul><p><img src="'+o+'" alt=""></p><hr><h2 id="快速开始" tabindex="-1">快速开始 <a class="header-anchor" href="#快速开始" aria-label="Permalink to “快速开始”">​</a></h2><ol><li>确认已订阅所需 <a href="/music-free-site/plugin-registry.html">注册表</a>（内置 + 可选社区）。</li><li>在插件商店安装插件，填写配置项并启用。</li><li>在 <strong>插件编排</strong> 中调整各维度插件顺序（可选）。</li><li>在 <a href="/music-free-site/music.html">音乐管理</a>、<a href="/music-free-site/playlist.html">歌单</a> 等页面验证搜索、刮削或导入效果。</li></ol><p>自行开发插件请参考 <a href="/music-free-site/plugin-development.html">插件开发</a> 与示例仓库 <a href="https://github.com/ansgoo/music-free-plugin" target="_blank" rel="noreferrer">music-free-plugin</a>。</p>',20)])])}const _=t(d,[["render",c]]);export{g as __pageData,_ as default};
